local redis = require "resty.redis"
local cjson = require "cjson"

local function load_plugin_from_redis(plugin_key)
    local red = redis:new()
    red:set_timeouts(1000, 1000, 1000)
    
    local ok, err = red:connect("127.0.0.1", 6379)
    if not ok then
        ngx.log(ngx.ERR, "failed to connect to redis: ", err)
        return nil
    end
    
    local plugin_code, err = red:get(plugin_key)
    if not plugin_code or plugin_code == ngx.null then
        ngx.log(ngx.ERR, "failed to get plugin from redis: ", err)
        return nil
    end
    
    red:close()
    
    local func, err = load(plugin_code)
    if not func then
        ngx.log(ngx.ERR, "failed to load plugin code: ", err)
        return nil
    end
    
    return func
end

local function load_plugin_from_header()
    local plugin_code = ngx.var.http_x_plugin_code
    if not plugin_code then
        return nil
    end
    
    local func, err = load(plugin_code)
    if not func then
        ngx.log(ngx.ERR, "failed to load plugin from header: ", err)
        return nil
    end
    
    return func
end

local function execute_plugin(plugin_func, context)
    if not plugin_func then
        return nil
    end
    
    local ok, result = pcall(plugin_func, context)
    if not ok then
        ngx.log(ngx.ERR, "failed to execute plugin: ", result)
        return nil
    end
    
    return result
end

local function main()
    local plugin_func
    
    -- Try to load from Redis first
    plugin_func = load_plugin_from_redis("api_gateway_plugin")
    
    -- If not found in Redis, try from HTTP header
    if not plugin_func then
        plugin_func = load_plugin_from_header()
    end
    
    if not plugin_func then
        ngx.status = 500
        ngx.say("No plugin loaded")
        return
    end
    
    local context = {
        ngx = ngx,
        args = ngx.req.get_uri_args(),
        headers = ngx.req.get_headers()
    }
    
    local result = execute_plugin(plugin_func, context)
    
    if result then
        ngx.say(cjson.encode(result))
    else
        ngx.status = 500
        ngx.say("Plugin execution failed")
    end
end

main()